const aiResponse = $input.first()?.json || {};
const inputData = $items('Parse Input Data')[0]?.json || {};

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content
    ?? raw?.data?.choices?.[0]?.message?.content
    ?? raw?.response?.choices?.[0]?.message?.content
    ?? '';
}

function parseModelJson(content) {
  try {
    const cleaned = String(content || '').replace(/```json/gi, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    const candidate = match ? match[0] : cleaned;
    return JSON.parse(candidate);
  } catch (e) {
    return null;
  }
}

const content = extractContent(aiResponse);
const parsed = parseModelJson(content);

if (!parsed) {
  return [{ json: { error: true, message: 'Failed to parse resume. Please ensure the resume text is clear and readable.', rawContent: content.substring(0, 500) } }];
}

const result = {
  error: false,
  fullName: parsed.fullName || inputData.candidateName || 'Candidate',
  email: parsed.email || inputData.candidateEmail || '',
  phone: parsed.phone || '',
  location: parsed.location || inputData.location || 'India',
  skills: Array.isArray(parsed.skills) ? parsed.skills : [],
  technicalSkills: Array.isArray(parsed.technicalSkills) ? parsed.technicalSkills : [],
  softSkills: Array.isArray(parsed.softSkills) ? parsed.softSkills : [],
  experience: Array.isArray(parsed.experience) ? parsed.experience : [],
  education: Array.isArray(parsed.education) ? parsed.education : [],
  certifications: Array.isArray(parsed.certifications) ? parsed.certifications : [],
  summary: parsed.summary || '',
  yearsOfExperience: Number(parsed.yearsOfExperience) || 0,
  primaryRole: parsed.primaryRole || 'Software Developer',
  industryKeywords: Array.isArray(parsed.industryKeywords) ? parsed.industryKeywords : [],
  fileName: inputData.fileName || 'resume.pdf',
  parsedAt: new Date().toISOString()
};

result.allSkills = [...new Set([...result.skills, ...result.technicalSkills, ...result.industryKeywords])];

return [{ json: result }];

