const resumeData = $items('Extract Resume Data')[0]?.json || {};
const keywordResponse = $input.first()?.json || {};

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content ?? raw?.data?.choices?.[0]?.message?.content ?? raw?.response?.choices?.[0]?.message?.content ?? '';
}

function parseModelJson(content) {
  try {
    const cleaned = String(content || '').replace(/```json/gi, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return JSON.parse(match ? match[0] : cleaned);
  } catch (e) {
    return null;
  }
}

const content = extractContent(keywordResponse);
const keywords = parseModelJson(content);

if (!keywords) {
  const fallbackKeywords = {
    primaryKeyword: resumeData.primaryRole || 'Software Developer',
    secondaryKeyword: resumeData.technicalSkills?.[0] || 'Developer',
    tertiaryKeyword: 'Software Engineer',
    searchStrategy: 'Using fallback keywords based on primary role',
    skillBasedKeywords: resumeData.allSkills?.slice(0, 3) || ['Developer']
  };
  return [{ json: { ...resumeData, keywords: fallbackKeywords } }];
}

return [{ json: { ...resumeData, keywords: { primaryKeyword: keywords.primaryKeyword || resumeData.primaryRole, secondaryKeyword: keywords.secondaryKeyword || '', tertiaryKeyword: keywords.tertiaryKeyword || '', searchStrategy: keywords.searchStrategy || '', skillBasedKeywords: Array.isArray(keywords.skillBasedKeywords) ? keywords.skillBasedKeywords : [] } } }];

const data = $input.first()?.json || {};
const keywords = data.keywords || {};
const searches = [];

if (keywords.primaryKeyword) searches.push({ json: { ...data, searchQuery: keywords.primaryKeyword, searchType: 'primary', searchIndex: 0 } });
if (keywords.secondaryKeyword) searches.push({ json: { ...data, searchQuery: keywords.secondaryKeyword, searchType: 'secondary', searchIndex: 1 } });
if (keywords.tertiaryKeyword) searches.push({ json: { ...data, searchQuery: keywords.tertiaryKeyword, searchType: 'tertiary', searchIndex: 2 } });

if (searches.length === 0) searches.push({ json: { ...data, searchQuery: data.primaryRole || 'Software Developer', searchType: 'fallback', searchIndex: 0 } });

return searches;

const adzunaResponse = $input.first()?.json || {};
const searchData = $items('Create Search Queries')[$itemIndex]?.json || {};
const results = Array.isArray(adzunaResponse.results) ? adzunaResponse.results : [];

if (results.length === 0) return [{ json: { ...searchData, jobs: [], jobsFound: 0, searchType: searchData.searchType } }];

const normalizedJobs = results.map((job, index) => ({
  id: `adzuna_${searchData.searchType}_${index}`,
  title: job.title || 'Unknown Role',
  company: job.company?.display_name || 'Unknown Company',
  location: job.location?.display_name || searchData.location || 'India',
  description: job.description || '',
  applyUrl: job.redirect_url || '',
  salaryMin: job.salary_min ?? null,
  salaryMax: job.salary_max ?? null,
  salaryIsEstimated: job.salary_is_predicted === '1',
  publishedAt: job.created || '',
  category: job.category?.label || '',
  contractType: job.contract_type || '',
  contractTime: job.contract_time || '',
  source: 'Adzuna',
  searchType: searchData.searchType,
  searchQuery: searchData.searchQuery
}));

return [{ json: { ...searchData, jobs: normalizedJobs, jobsFound: normalizedJobs.length } }];

const allItems = $input.all();
const resumeData = $items('Merge Keywords with Profile')[0]?.json || {};
let allJobs = [];
let totalFound = 0;

for (const item of allItems) {
  const data = item.json || {};
  if (Array.isArray(data.jobs)) { allJobs = allJobs.concat(data.jobs); totalFound += data.jobsFound || 0; }
}

const seen = new Set();
const uniqueJobs = allJobs.filter(job => {
  const key = `${job.company?.toLowerCase()}_${job.title?.toLowerCase()}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const jobsToScore = uniqueJobs.slice(0, 30);

return jobsToScore.map(job => ({ json: { ...resumeData, jobTitle: job.title, company: job.company, jobLocation: job.location, jobDescription: job.description, applyUrl: job.applyUrl, salaryMin: job.salaryMin, salaryMax: job.salaryMax, salaryIsEstimated: job.salaryIsEstimated, publishedAt: job.publishedAt, category: job.category, contractType: job.contractType, contractTime: job.contractTime, source: job.source, searchType: job.searchType, jobId: job.id, totalJobsFound: totalFound, uniqueJobsFound: uniqueJobs.length } }));

