const scoredItems = $input.all();
const jobItems = $items('Combine and Deduplicate Jobs');
const resumeData = $items('Merge Keywords with Profile')[0]?.json || {};
const threshold = 5;

function extractContent(raw) { return raw?.choices?.[0]?.message?.content ?? raw?.data?.choices?.[0]?.message?.content ?? raw?.response?.choices?.[0]?.message?.content ?? ''; }

function parseModelJson(content) {
  try {
    const cleaned = String(content || '').replace(/```json/gi, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return JSON.parse(match ? match[0] : cleaned);
  } catch (e) { return { score: 0, reason: 'Parse error', skillsMatch: [], skillsGap: [], fitLevel: 'poor' }; }
}

const matches = [];
for (let i = 0; i < scoredItems.length; i++) {
  const raw = scoredItems[i].json || {};
  const job = jobItems[i]?.json || {};
  const parsed = parseModelJson(extractContent(raw));
  const score = Math.max(0, Math.min(10, Number(parsed.score) || 0));
  if (score < threshold) continue;
  matches.push({ jobTitle: job.jobTitle, company: job.company, jobLocation: job.jobLocation, jobDescription: job.jobDescription, applyUrl: job.applyUrl, salaryMin: job.salaryMin, salaryMax: job.salaryMax, salaryIsEstimated: job.salaryIsEstimated, publishedAt: job.publishedAt, category: job.category, contractType: job.contractType, contractTime: job.contractTime, source: job.source, score, reason: parsed.reason || '', skillsMatch: Array.isArray(parsed.skillsMatch) ? parsed.skillsMatch : [], skillsGap: Array.isArray(parsed.skillsGap) ? parsed.skillsGap : [], fitLevel: parsed.fitLevel || 'fair' });
}

matches.sort((a, b) => b.score - a.score);
const topMatches = matches.slice(0, 8);

return [{ json: { ...resumeData, allScoredJobs: matches, topJobs: topMatches, totalScored: scoredItems.length, totalMatched: matches.length, topJobsCount: topMatches.length, timestamp: new Date().toISOString() } }];

