const rankedJobs = $items('Aggregate and Rank Jobs')[0]?.json || {};
const guidanceResponse = $input.first()?.json || {};

function extractContent(raw) { return raw?.choices?.[0]?.message?.content ?? raw?.data?.choices?.[0]?.message?.content ?? raw?.response?.choices?.[0]?.message?.content ?? ''; }

const careerGuidance = extractContent(guidanceResponse);

const emailDrafts = rankedJobs.topJobs?.map((job, index) => {
  const subject = `Application for ${job.jobTitle} Position at ${job.company}`;
  const body = [
    `Dear ${job.company} Hiring Team,`,
    '',
    `I am writing to express my strong interest in the ${job.jobTitle} position at ${job.company}.`,
    '',
    `With ${rankedJobs.yearsOfExperience || 'relevant'} years of experience in ${rankedJobs.primaryRole || 'software development'}, I believe I would be a valuable addition to your team.`,
    '',
    `Key qualifications that align with this role:`,
    ...job.skillsMatch.map(s => `• ${s}`),
    '',
    `My technical expertise includes: ${rankedJobs.technicalSkills?.slice(0, 5).join(', ') || rankedJobs.allSkills?.slice(0, 5).join(', ')}`,
    '',
    `I am particularly drawn to this opportunity because: ${job.reason}`,
    '',
    `I have attached my resume for your review and would welcome the opportunity to discuss how my skills and experience can contribute to ${job.company}'s continued success.`,
    '',
    'Thank you for your consideration.',
    '',
    'Best regards,',
    rankedJobs.fullName || 'Candidate'
  ].join('\n');

  return { to: '', subject, body, company: job.company, jobTitle: job.jobTitle, applyUrl: job.applyUrl, score: job.score, fitLevel: job.fitLevel };
}) || [];

return [{ json: { status: 'success', candidateName: rankedJobs.fullName, candidateEmail: rankedJobs.email, candidatePhone: rankedJobs.phone, candidateLocation: rankedJobs.location, primaryRole: rankedJobs.primaryRole, skills: rankedJobs.allSkills, technicalSkills: rankedJobs.technicalSkills, yearsOfExperience: rankedJobs.yearsOfExperience, keywords: rankedJobs.keywords, totalJobsFound: rankedJobs.totalJobsFound || 0, uniqueJobsFound: rankedJobs.uniqueJobsFound || 0, totalScored: rankedJobs.totalScored || 0, totalMatched: rankedJobs.totalMatched || 0, topJobs: rankedJobs.topJobs || [], allScoredJobs: rankedJobs.allScoredJobs || [], emailDrafts, careerGuidance: careerGuidance || 'Career guidance not available', timestamp: new Date().toISOString() } }];

const data = $items('Build Final Response')[0]?.json || {};
let output = '';

if (data.error) {
  output = `❌ ${data.message}`;
} else {
  output = `✅ **Resume Analysis Complete!**\n\n`;
  output += `👤 **Candidate:** ${data.candidateName}\n`;
  output += `🎯 **Target Role:** ${data.primaryRole}\n`;
  output += `📍 **Location:** ${data.candidateLocation}\n`;
  output += `💼 **Experience:** ${data.yearsOfExperience} years\n\n`;
  output += `🔑 **Your Skills:** ${data.skills?.slice(0, 10).join(', ')}${data.skills?.length > 10 ? '...' : ''}\n\n`;
  output += `🔍 **Search Keywords Used:**\n`;
  output += `• Primary: ${data.keywords?.primaryKeyword}\n`;
  if (data.keywords?.secondaryKeyword) output += `• Secondary: ${data.keywords?.secondaryKeyword}\n`;
  if (data.keywords?.tertiaryKeyword) output += `• Tertiary: ${data.keywords?.tertiaryKeyword}\n`;
  output += `\n📊 **Results:** Found ${data.uniqueJobsFound} unique jobs, scored ${data.totalScored}, matched ${data.totalMatched}\n\n`;
  if (data.topJobs?.length > 0) {
    output += `🏆 **TOP ${data.topJobs.length} MATCHING JOBS:**\n\n`;
    data.topJobs.forEach((job, i) => {
      output += `**${i + 1}. ${job.jobTitle}** at ${job.company}\n`;
      output += `   📍 ${job.jobLocation}\n`;
      if (job.salaryMin || job.salaryMax) output += `   💰 ₹${job.salaryMin?.toLocaleString() || '?'} - ₹${job.salaryMax?.toLocaleString() || '?'}${job.salaryIsEstimated ? ' (estimated)' : ''}\n`;
      output += `   ⭐ Score: ${job.score}/10 (${job.fitLevel})\n`;
      output += `   📝 ${job.reason}\n`;
      if (job.skillsMatch?.length > 0) output += `   ✅ Matching: ${job.skillsMatch.join(', ')}\n`;
      if (job.skillsGap?.length > 0) output += `   📚 Skills to learn: ${job.skillsGap.join(', ')}\n`;
      output += `   🔗 Apply: ${job.applyUrl}\n\n`;
    });
  } else {
    output += `⚠️ No strong matches found. Consider broadening your search or developing additional skills.\n\n`;
  }
  output += `📧 **Email drafts prepared for top ${data.emailDrafts?.length || 0} companies**\n\n`;
  output += `💡 **Career Guidance:**\n${data.careerGuidance}`;
}

return [{ json: { response: output, data: data } }];
